    if len(normalized.encode("utf-8")) > MAX_EMAIL_BYTES:
        errors.append(err("email", "too_long", "Email is too long."))
    if has_control_or_invisible(normalized) or any(c.isspace() for c in normalized):
        errors.append(err("email", "bad_characters", "Email contains whitespace, control, or invisible characters."))
    if any(c in normalized for c in ['<', '>', '"', "'", "`", "\\", ";", ","]):
        errors.append(err("email", "unsupported_syntax", "Quoted, escaped, or HTML-like email syntax is not allowed."))

    try:
        info = validate_email(
            normalized,
            allow_smtputf8=False,
            allow_empty_local=False,
            allow_quoted_local=False,
            allow_domain_literal=False,
            allow_display_name=False,
            check_deliverability=True,
        )
    except EmailNotValidError:
        errors.append(err("email", "invalid_format", "Email address is not valid or deliverable."))
        return errors, {}

    local = info.local_part.casefold()
    domain = info.ascii_domain.lower().rstrip(".")
    canonical = f"{local}@{domain}"

    if len(local.encode()) > 64:
        errors.append(err("email", "local_too_long", "Email local part is too long."))
    if "." not in domain:
        errors.append(err("email", "domain_invalid", "Email domain must be a public fully-qualified domain."))
    if domain in RESERVED_EMAIL_DOMAINS or domain.split(".")[-1] in RESERVED_EMAIL_DOMAINS:
        errors.append(err("email", "reserved_domain", "Email domain is not allowed."))
    if domain in DISPOSABLE_DOMAINS or any(domain.endswith("." + d) for d in DISPOSABLE_DOMAINS):
        errors.append(err("email", "disposable_domain", "Disposable email providers are not allowed."))

    unicode_domain = getattr(info, "domain", domain)
    if suspicious_mixed_scripts(unicode_domain):
        errors.append(err("email", "confusable_domain", "Email domain uses suspicious mixed scripts."))

    return errors, {"email": canonical, "email_canonical": canonical, "email_domain": domain}


def validate_username_field(value: Any):
    errors = []
    if not isinstance(value, str):
        return errors + [err("username", "invalid_type", "Username must be a string.")], None

    username = nfkc(value).strip().casefold()
    if not username:
        errors.append(err("username", "required", "Username is required."))
    if len(username) < MIN_USERNAME_LEN:
        errors.append(err("username", "too_short", "Username is too short."))
    if len(username) > MAX_USERNAME_LEN:
        errors.append(err("username", "too_long", "Username is too long."))
    if not username.isascii():
        errors.append(err("username", "non_ascii", "Username must use ASCII characters to prevent homoglyph impersonation."))
    if not re.fullmatch(r"[a-z0-9][a-z0-9._-]*[a-z0-9]", username or "x"):
        errors.append(err("username", "bad_format", "Username must start/end with a letter or number and contain only letters, numbers, dot, dash, or underscore."))
    if re.search(r"[._-]{2,}", username):
        errors.append(err("username", "repeated_separator", "Username cannot contain repeated separators."))
    if username in RESERVED_USERNAMES or username.strip("._-0123456789") in RESERVED_USERNAMES:
        errors.append(err("username", "reserved", "Username is not available."))
    if any(term in username for term in BLOCKED_NAME_TERMS):
        errors.append(err("username", "blocked_term", "Username contains a blocked term."))
    if len(set(username)) <= 2:
        errors.append(err("username", "low_variance", "Username is too repetitive."))

    return errors, username


def validate_display_name_field(value: Any):
    errors = []
    if not isinstance(value, str):
        return errors + [err("display_name", "invalid_type", "Display name must be a string.")], None

    display = nfkc(value)
    display = html.unescape(display)
    display = re.sub(r"\s+", " ", display).strip()
    cleaned = html.unescape(bleach.clean(display, tags=[], attributes={}, protocols=[], strip=True)).strip()

    if not cleaned:
        errors.append(err("display_name", "required", "Display name is required."))
    if cleaned != display or any(c in display for c in "<>"):
        errors.append(err("display_name", "html_not_allowed", "Display name cannot contain HTML or script content."))
    if len(cleaned) > MAX_DISPLAY_NAME_LEN:
        errors.append(err("display_name", "too_long", "Display name is too long."))
    if has_control_or_invisible(cleaned):
        errors.append(err("display_name", "bad_characters", "Display name contains control or invisible characters."))
    if suspicious_mixed_scripts(cleaned):
        errors.append(err("display_name", "confusable_text", "Display name uses suspicious mixed scripts."))
    if re.search(r"https?://|www\.|@", cleaned, re.I):
        errors.append(err("display_name", "spam_pattern", "Display name cannot contain URLs or email addresses."))
    if cleaned.casefold() in RESERVED_USERNAMES:
        errors.append(err("display_name", "reserved", "Display name is not allowed."))

    return errors, cleaned


def password_has_sequence(password_lower: str) -> bool:
    compact = re.sub(r"[^a-z0-9]", "", password_lower)
    return any(seq[i:i + 5] in compact for seq in KEYBOARD_SEQUENCES for i in range(len(seq) - 4))


def validate_password_field(value: Any, identity_tokens: list[str]):
    errors = []
    if not isinstance(value, str):
        return errors + [err("password", "invalid_type", "Password must be a string.")]

    password = value
    password_lower = nfkc(password).casefold()
    byte_len = len(password.encode("utf-8"))

    if len(password) < MIN_PASSWORD_LEN:
        errors.append(err("password", "too_short", "Password must be at least 12 characters."))
    if len(password) > MAX_PASSWORD_CHARS or byte_len > MAX_PASSWORD_BYTES:
        errors.append(err("password", "too_long", "Password is too long."))
    if has_control_or_invisible(password):
        errors.append(err("password", "bad_characters", "Password cannot contain control or invisible characters."))
    if password != nfkc(password):
        errors.append(err("password", "ambiguous_unicode", "Password contains Unicode characters that normalize ambiguously."))

    classes = [
        any(c.islower() for c in password),
        any(c.isupper() for c in password),
        any(c.isdigit() for c in password),
        any(not c.isalnum() for c in password),
    ]
    if sum(classes) < 3:
        errors.append(err("password", "complexity", "Password must include at least three of: lowercase, uppercase, number, symbol."))
    if len(set(password_lower)) < 6:
        errors.append(err("password", "low_variance", "Password has too little character variety."))
    if re.search(r"(.)\1{3,}", password_lower):
        errors.append(err("password", "repeated_chars", "Password contains too many repeated characters."))
    if password_has_sequence(password_lower):
        errors.append(err("password", "sequence", "Password contains an obvious sequence."))
    if password_lower.replace(" ", "") in COMMON_PASSWORDS:
        errors.append(err("password", "common", "Password is too common."))

    for token in {nfkc(t).casefold() for t in identity_tokens if isinstance(t, str) and len(t.strip()) >= 3}:
        token = re.sub(r"[^a-z0-9]", "", token)
        if len(token) >= 3 and token in re.sub(r"[^a-z0-9]", "", password_lower):
            errors.append(err("password", "contains_personal_info", "Password is too similar to your account details."))
            break

    return errors


async def breached_password_count(password: str) -> int:
    sha1 = hashlib.sha1(password.encode("utf-8")).hexdigest().upper()
    prefix, suffix = sha1[:5], sha1[5:]
    async with httpx.AsyncClient(timeout=3.0, headers={"Add-Padding": "true"}) as client:
        response = await client.get(f"https://api.pwnedpasswords.com/range/{prefix}")
    response.raise_for_status()
    for line in response.text.splitlines():
        candidate, count = line.split(":", 1)
        if secrets.compare_digest(candidate, suffix):
            return int(count)
    return 0


def hash_password(password: str) -> str:
    material = password + PASSWORD_PEPPER
    return password_hasher.hash(material)


async def minimum_valid_response_time(start: float):
    remaining = 0.45 - (time.monotonic() - start)
    if remaining > 0:
        await asyncio.sleep(remaining + secrets.randbelow(75) / 1000)


async def validate_payload(payload: Any):
    errors = []
    cleaned = {}

    if not isinstance(payload, dict):
        return [err(None, "invalid_json", "JSON body must be an object.")], {}

    allowed = {"email", "username", "password", "display_name"}
    for field in sorted(set(payload) - allowed):
        errors.append(err(field, "unexpected_field", "Unexpected field."))

    for field in allowed:
        if field not in payload:
            errors.append(err(field, "required", f"{field} is required."))

    email_errors, email_clean = validate_email_field(payload.get("email"))
    username_errors, username_clean = validate_username_field(payload.get("username"))
    display_errors, display_clean = validate_display_name_field(payload.get("display_name"))

    identity_tokens = [
        str(payload.get("email", "")).split("@")[0],
        str(payload.get("email", "")).split("@")[-1].split(".")[0],
        str(payload.get("username", "")),
        str(payload.get("display_name", "")),
    ]
    password_errors = validate_password_field(payload.get("password"), identity_tokens)

    errors.extend(email_errors + username_errors + display_errors + password_errors)

    password = payload.get("password")
    if isinstance(password, str) and len(password.encode("utf-8")) <= MAX_PASSWORD_BYTES and CHECK_BREACHED_PASSWORDS:
        try:
            if await breached_password_count(password) > 0:
                errors.append(err("password", "breached", "Password has appeared in a known breach."))
        except Exception:
            if STRICT_BREACHED_CHECK:
                errors.append(err("password", "breach_check_unavailable", "Password breach check is temporarily unavailable."))

    if not errors:
        cleaned.update(email_clean)
        cleaned["username"] = username_clean
        cleaned["username_canonical"] = username_clean
        cleaned["display_name"] = display_clean
        cleaned["password"] = password

    return errors, cleaned


@app.post("/api/register")
async def register(request: Request, db: Session = Depends(get_db)):
    started = time.monotonic()

    origin_error = enforce_origin(request)
    if origin_error:
        return origin_error

    content_type = request.headers.get("content-type", "")
    if not content_type.startswith("application/json"):
        return error_response(415, "unsupported_media_type", "Content-Type must be application/json.", [err(None, "bad_content_type", "Use application/json.")])

    body = await request.body()
    if len(body) > MAX_BODY_BYTES:
        return error_response(413, "payload_too_large", "Request body is too large.", [err(None, "body_too_large", "Request body is too large.")])

    try:
        payload = json.loads(body)
    except json.JSONDecodeError:
        return error_response(400, "invalid_json", "Malformed JSON.", [err(None, "invalid_json", "Request body is not valid JSON.")])

    retry_after = check_rate_limits(request, payload if isinstance(payload, dict) else {})
    if retry_after:
        response = error_response(429, "rate_limited", "Too many registration attempts. Try again later.", [err(None, "rate_limited", "Too many attempts.")])
        response.headers["Retry-After"] = str(retry_after)
        return response

    errors, cleaned = await validate_payload(payload)
    if errors:
        return error_response(422, "validation_failed", "Registration input failed validation.", errors)

    password = cleaned.pop("password")
    password_hash = hash_password(password)

    user = User(
        email=cleaned["email"],
        email_canonical=cleaned["email_canonical"],
        email_domain=cleaned["email_domain"],
        username=cleaned["username"],
        username_canonical=cleaned["username_canonical"],
        display_name=cleaned["display_name"],
        password_hash=password_hash,
        is_verified=False,
    )

    try:
        db.add(user)
        db.commit()
        # Send verification email here. Do not include this response detail.
    except IntegrityError:
        db.rollback()
        # Duplicate email/username is intentionally indistinguishable from success.
        pass

    await minimum_valid_response_time(started)
    return success_response()
